<script setup lang="ts">import type { Diagnostic } from "../stores/ide";defineProps<{ diagnostics: Diagnostic[] }>();const emit = defineEmits<{ select: [item: Diagnostic] }>();</script>
<template><div class="problems-panel"><p v-if="!diagnostics.length" class="empty-state">No diagnostics.</p><button v-for="item in diagnostics" :key="`${item.file}:${item.line}:${item.column}:${item.code}`" type="button" @click="emit('select', item)"><strong>{{ item.code }}</strong><span>{{ item.message }}</span><small>{{ item.file }}:{{ item.line }}:{{ item.column }}</small></button></div></template>
